### 2. Update Selection Logic
```rust
pub async fn select_worker(
    pool: &WorkerPool,
    request: &SelectionRequest,
    weights: &SelectionWeights,
) -> SelectionResponse {
    // Get all workers
    let all_workers = pool.all_workers().await;

    if all_workers.is_empty() {
        return SelectionResponse::no_worker(SelectionReason::NoWorkersConfigured);
    }

    // Filter to available workers (healthy/degraded + circuit closed)
    let mut available = Vec::new();
    let mut all_circuits_open = true;
    let mut all_unreachable = true;

    for worker in all_workers {
        let status = worker.status().await;
        let circuit = worker.circuit_state().await;

        if !matches!(status, WorkerStatus::Unreachable | WorkerStatus::Disabled) {
            all_unreachable = false;
        }

        if circuit.is_closed() {
            all_circuits_open = false;
            if matches!(status, WorkerStatus::Healthy | WorkerStatus::Degraded) {
                available.push(worker);
            }
        }
    }

    if available.is_empty() {
        let reason = if all_unreachable {
            SelectionReason::AllWorkersUnreachable
        } else if all_circuits_open {
            SelectionReason::AllCircuitsOpen
        } else {
            SelectionReason::AllWorkersBusy
        };
        return SelectionResponse::no_worker(reason);
    }

    // Filter by slot availability
    let with_slots: Vec<_> = available
        .into_iter()
        .filter(|w| w.available_slots() >= request.required_cores)
        .collect();

    if with_slots.is_empty() {
        return SelectionResponse::no_worker(SelectionReason::AllWorkersBusy);
    }

    // Score and select best worker
    let scored: Vec<_> = with_slots
        .into_iter()
        .map(|w| {
            let score = calculate_score(&w, request, weights);
            (w, score)
        })
        .collect();

    let best = scored
        .into_iter()
        .max_by(|a, b| a.1.partial_cmp(&b.1).unwrap())
